// Initialize automation execution
const startTime = new Date();
const executionId = $execution.id;

// Define containers to update (excluding critical systems)
const containers = [
  {id: '100', name: 'postoffice', critical: 'high'},
  {id: '105', name: 'authentik-proxy', critical: 'high'},
  {id: '107', name: 'npmplus', critical: 'medium'},
  {id: '108', name: 'bookstack', critical: 'low'},
  {id: '109', name: 'wazuh', critical: 'high'},
  {id: '115', name: 'stream', critical: 'low'},
  {id: '117', name: 'dev1rawgle', critical: 'low'},
  {id: '118', name: 'test-stack', critical: 'low'},
  {id: '119', name: 'jupyter-notebook', critical: 'low'},
  {id: '150', name: 'apt-cacher', critical: 'medium'}
];

console.log(`Starting automation for ${containers.length} containers at ${startTime}`);

return {
  containers: containers,
  execution: {
    id: executionId,
    startTime: startTime.toISOString(),
    totalContainers: containers.length
  }
};

// Log successful update
const container = $json.containers[$splitInBatches.index];
const success = $json.exitCode === 0;
const endTime = new Date();

console.log(`Container ${container.id} (${container.name}): Update ${success ? 'successful' : 'failed'}`);

return {
  container_id: container.id,
  container_name: container.name,
  status: success ? 'completed' : 'failed',
  success: success,
  timestamp: endTime.toISOString(),
  exitCode: $json.exitCode,
  output: $json.stdout || '',
  error: $json.stderr || ''
};

// Log skipped container
const container = $json.containers[$splitInBatches.index];
const reason = $json.stdout && $json.stdout.includes('status: running') ? 'No updates available' : 'Container not running';

console.log(`Container ${container.id} (${container.name}): Skipped - ${reason}`);

return {
  container_id: container.id,
  container_name: container.name,
  status: 'skipped',
  success: null,
  timestamp: new Date().toISOString(),
  reason: reason
};

// Generate execution summary
const endTime = new Date();
const allResults = $input.all();

// Count results
const successful = allResults.filter(item => item.json.success === true).length;
const failed = allResults.filter(item => item.json.success === false).length;
const skipped = allResults.filter(item => item.json.status === 'skipped').length;

const summary = {
  execution_date: new Date().toISOString().split('T')[0],
  total_containers: allResults.length,
  successful_updates: successful,
  failed_updates: failed,
  skipped_containers: skipped,
  execution_end_time: endTime.toISOString(),
  overall_status: failed > 0 ? 'partial_failure' : 'completed'
};

console.log(`Automation Summary: ${successful} successful, ${failed} failed, ${skipped} skipped`);

return { summary };
